2045	func (w *ExecuteBeadWorker) nextCandidate(ctx context.Context, results []ExecuteBeadReport, guards []work.Guard, labelFilter, targetBeadID string) (bead.Bead, []pickerSkip, bool, error) {
2046		// Use PreviewQueue for the stable filter+sort logic. Limit=0 returns all
2047		// entries so we can scan for the first candidate not already present in
2048		// the current drain results slice.
2049		entries, err := PreviewQueue(w.Store, PickerFilters{LabelFilter: labelFilter}, 0)
2050		if err != nil {
2051			return bead.Bead{}, nil, false, err
2052		}
2053	
2054		// Rebuild the ready list from the preview entries in picker order so we
2055		// can apply the per-run drain results slice on top. We need the original
2056		// bead values for the return; fetch them from ReadyExecution (already
2057		// ordered).
2058		ready, err := w.Store.ReadyExecution()
2059		if err != nil {
2060			return bead.Bead{}, nil, false, err
2061		}
2062		// Index by ID for O(1) lookup.
2063		byID := make(map[string]bead.Bead, len(ready))
2064		for _, b := range ready {
2065			byID[b.ID] = b
2066		}
2067		var skips []pickerSkip
2068		for _, entry := range entries {
2069			candidate, ok := byID[entry.BeadID]
2070			if !ok {
2071				// Should not happen; skip defensively.
2072				continue
2073			}
2074			if targetBeadID != "" && candidate.ID != targetBeadID {
2075				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "target_bead"})
2076				continue
2077			}
2078			if hasResultForBead(results, candidate.ID) {
2079				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "in_attempted"})
2080				continue
2081			}
2082			if entry.FilterDecision == FilterDecisionSkipped {
2083				// PreviewQueue already applied label_filter; record as skip.
2084				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "label_filter"})
2085				continue
2086			}
2087			allowed := true
2088			for _, guard := range guards {
2089				if guard == nil {
2090					continue
2091				}
2092				ok, reason := guard.Allow(ctx, candidate.ID)
2093				if ok {
2094					continue
2095				}
2096				allowed = false
2097				if reason != "" {
2098					skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: reason})
2099				}
2100				break
2101			}
2102			if !allowed {
2103				continue
2104			}
2105			return candidate, skips, true, nil
2106		}
2107		return bead.Bead{}, skips, false, nil
2108	}
