89			ObservedAt:      time.Now().UTC(),
90			Success:         result.ExitCode == 0 && result.Error == "",
91			LatencyMS:       int(elapsed.Milliseconds()),
92			InputTokens:     result.InputTokens,
93			OutputTokens:    result.OutputTokens,
94			CostUSD:         result.CostUSD,
95			NativeSessionID: result.AgentSessionID,
