5		"bytes"
6		"encoding/json"
7		"io"
8		"os"
9	)
10	
11	// ForEachJSONL opens path and calls fn for each valid JSON record.
12	// Malformed lines are skipped. Missing files are treated as empty.
13	// Handles lines of any length.
14	func ForEachJSONL[T any](path string, fn func(T) error) error {
15		f, err := os.Open(path)
16		if os.IsNotExist(err) {
17			return nil
18		}
19		if err != nil {
20			return err
21		}
22		defer f.Close()
23		return scanJSONLReader[T](f, fn)
24	}
25	
26	// ReadAllJSONL loads all records from a JSONL file into a slice.
27	func ReadAllJSONL[T any](path string) ([]T, error) {
28		var records []T
29		err := ForEachJSONL[T](path, func(rec T) error {
30			records = append(records, rec)
31			return nil
32		})
33		return records, err
34	}
35	
36	// scanJSONLReader reads newline-delimited JSON records from r, calling fn for each valid record.
37	// It uses bufio.Reader.ReadBytes so there is no line-length limit.
38	func scanJSONLReader[T any](r io.Reader, fn func(T) error) error {
39		reader := bufio.NewReader(r)
40		for {
41			line, err := reader.ReadBytes('\n')
42			line = bytes.TrimSpace(line)
43			if len(line) > 0 {
44				var rec T
45				if jsonErr := json.Unmarshal(line, &rec); jsonErr == nil {
46					if fnErr := fn(rec); fnErr != nil {
47						return fnErr
48					}
49				}
50			}
51			if err == io.EOF {
52				break
53			}
54			if err != nil {
55				return err
56			}
57		}
58		return nil
59	}
