package agent

import (
	"os"
	"path/filepath"
	"time"
)

const (
	// AttemptMetricsSchemaVersion is the schema_version written to every row.
	AttemptMetricsSchemaVersion = 1
	attemptMetricsDir           = ".ddx/metrics"
	attemptMetricsFile          = "attempts.jsonl"
)

// AttemptMetricsRow is one per-bead-attempt row in .ddx/metrics/attempts.jsonl.
// JSONL append-only; schema_version enables future migrations.
type AttemptMetricsRow struct {
	SchemaVersion               int            `json:"schema_version"`
	AttemptID                   string         `json:"attempt_id"`
	BeadID                      string         `json:"bead_id"`
	SessionID                   string         `json:"session_id,omitempty"`
	TsStart                     time.Time      `json:"ts_start"`
	TsEnd                       time.Time      `json:"ts_end"`
	Model                       string         `json:"model,omitempty"`
	Harness                     string         `json:"harness,omitempty"`
	Profile                     string         `json:"profile,omitempty"`
	Provider                    string         `json:"provider,omitempty"`
	PromptTemplateID            string         `json:"prompt_template_id,omitempty"`
	PromptTemplateHash          string         `json:"prompt_template_hash,omitempty"`
	SpecID                      string         `json:"spec_id,omitempty"`
	Outcome                     string         `json:"outcome"`
	ExitCode                    int            `json:"exit_code"`
	CostUSD                     float64        `json:"cost_usd"`
	DurationMS                  int64          `json:"duration_ms"`
	InputTokens                 int            `json:"input_tokens,omitempty"`
	OutputTokens                int            `json:"output_tokens,omitempty"`
	TotalTokens                 int            `json:"total_tokens,omitempty"`
	ReviewVerdict               string         `json:"review_verdict,omitempty"`
	ReviewFindingCountBySeverity map[string]int `json:"review_finding_count_by_severity,omitempty"`
	LadderMinPowerInitial       int            `json:"ladder_min_power_initial,omitempty"`
	LadderMinPowerFinal         int            `json:"ladder_min_power_final,omitempty"`
	LadderStepsTaken            int            `json:"ladder_steps_taken,omitempty"`
}

// AttemptMetricsStore persists per-attempt metrics rows.
type AttemptMetricsStore struct {
	ProjectRoot string
}

// NewAttemptMetricsStore returns a store rooted at projectRoot.
func NewAttemptMetricsStore(projectRoot string) *AttemptMetricsStore {
	return &AttemptMetricsStore{ProjectRoot: projectRoot}
}

func (s *AttemptMetricsStore) attemptsPath() string {
	return filepath.Join(s.ProjectRoot, attemptMetricsDir, attemptMetricsFile)
}

// AppendRow appends one row to attempts.jsonl using O_APPEND for atomic single-writer appends.
func (s *AttemptMetricsStore) AppendRow(row AttemptMetricsRow) error {
	p := s.attemptsPath()
	if err := os.MkdirAll(filepath.Dir(p), 0o755); err != nil {
		return err
	}
	return appendJSONLRecord(p, row)
}

// ReadRows loads all rows from attempts.jsonl.
func (s *AttemptMetricsStore) ReadRows() ([]AttemptMetricsRow, error) {
	return ReadAllJSONL[AttemptMetricsRow](s.attemptsPath())
}

// metricsRowFromReport builds an AttemptMetricsRow from an ExecuteBeadReport.
// tsEnd is the wall-clock time at the finalization point.
func metricsRowFromReport(report ExecuteBeadReport, tsEnd time.Time) AttemptMetricsRow {
	tsStart := tsEnd.Add(-time.Duration(report.DurationMS) * time.Millisecond)
	return AttemptMetricsRow{
		SchemaVersion:         AttemptMetricsSchemaVersion,
		AttemptID:             report.AttemptID,
		BeadID:                report.BeadID,
		SessionID:             report.SessionID,
		TsStart:               tsStart.UTC(),
		TsEnd:                 tsEnd.UTC(),
		Model:                 report.Model,
		Harness:               report.Harness,
		Provider:              report.Provider,
		Outcome:               report.Status,
		CostUSD:               report.CostUSD,
		DurationMS:            report.DurationMS,
		ReviewVerdict:         report.ReviewVerdict,
		LadderMinPowerInitial: report.PredictedPower,
		LadderMinPowerFinal:   report.ActualPower,
		LadderStepsTaken:      report.EscalationCount,
	}
}

// appendAttemptMetrics appends a row to .ddx/metrics/attempts.jsonl.
// Errors are silently swallowed — metrics recording must never break the execute-loop.
func appendAttemptMetrics(projectRoot string, report ExecuteBeadReport, tsEnd time.Time) {
	if projectRoot == "" || report.BeadID == "" {
		return
	}
	row := metricsRowFromReport(report, tsEnd)
	_ = NewAttemptMetricsStore(projectRoot).AppendRow(row)
}

package agent

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

// beadEventForBackfill is the JSON shape of one line in a bead's events.jsonl.
type beadEventForBackfill struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Source    string    `json:"source,omitempty"`
	CreatedAt time.Time `json:"created_at"`
}

// costEventBody is the JSON body of a "cost" event emitted by ddx agent execute-bead.
type costEventBody struct {
	AttemptID    string  `json:"attempt_id"`
	Harness      string  `json:"harness,omitempty"`
	Provider     string  `json:"provider,omitempty"`
	Model        string  `json:"model,omitempty"`
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	DurationMS   int64   `json:"duration_ms"`
	ExitCode     int     `json:"exit_code"`
}

// routingEventBodyForBackfill is the JSON body of a "routing" event from execute-bead.
type routingEventBodyForBackfill struct {
	ResolvedProvider string `json:"resolved_provider"`
	ResolvedModel    string `json:"resolved_model"`
}

// BackfillAttemptMetrics scans .ddx/attachments/<bead-id>/events.jsonl for
// every bead and emits one row per attempt. Idempotent: rows whose attempt_id
// already appears in .ddx/metrics/attempts.jsonl are skipped. Returns the
// number of new rows appended.
func BackfillAttemptMetrics(projectRoot string) (int, error) {
	store := NewAttemptMetricsStore(projectRoot)

	existing, err := store.ReadRows()
	if err != nil {
		return 0, fmt.Errorf("backfill: read existing rows: %w", err)
	}
	seen := make(map[string]struct{}, len(existing))
	for _, row := range existing {
		if row.AttemptID != "" {
			seen[row.AttemptID] = struct{}{}
		}
	}

	attachDir := filepath.Join(projectRoot, ".ddx", "attachments")
	entries, err := os.ReadDir(attachDir)
	if err != nil {
		if os.IsNotExist(err) {
			return 0, nil
		}
		return 0, fmt.Errorf("backfill: list attachments: %w", err)
	}

	added := 0
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		beadID := entry.Name()
		eventsFile := filepath.Join(attachDir, beadID, "events.jsonl")
		rows, extractErr := extractRowsFromBeadEvents(beadID, eventsFile)
		if extractErr != nil {
			continue
		}
		for _, row := range rows {
			if row.AttemptID == "" {
				continue
			}
			if _, ok := seen[row.AttemptID]; ok {
				continue
			}
			if appendErr := store.AppendRow(row); appendErr != nil {
				continue
			}
			seen[row.AttemptID] = struct{}{}
			added++
		}
	}
	return added, nil
}

// extractRowsFromBeadEvents builds AttemptMetricsRow values from a bead's events.jsonl.
// It uses "cost" events as the primary attempt source: each cost event pairs with
// the next "execute-bead" event for the outcome. "routing" events from
// "ddx agent execute-bead" preceding a cost event supply provider/model when absent
// from the cost body. "review" events between cost and execute-bead supply the verdict.
func extractRowsFromBeadEvents(beadID, eventsFile string) ([]AttemptMetricsRow, error) {
	var events []beadEventForBackfill
	if err := ForEachJSONL[beadEventForBackfill](eventsFile, func(ev beadEventForBackfill) error {
		events = append(events, ev)
		return nil
	}); err != nil {
		return nil, err
	}

	type pendingAttempt struct {
		row    AttemptMetricsRow
		closed bool
	}

	var rows []AttemptMetricsRow
	var lastProvider, lastModel string
	var pending *pendingAttempt

	for _, ev := range events {
		switch ev.Kind {
		case "routing":
			if ev.Source == "ddx agent execute-bead" {
				var rb routingEventBodyForBackfill
				if json.Unmarshal([]byte(ev.Body), &rb) == nil {
					lastProvider = rb.ResolvedProvider
					lastModel = rb.ResolvedModel
				}
			}

		case "cost":
			var cb costEventBody
			if json.Unmarshal([]byte(ev.Body), &cb) != nil || cb.AttemptID == "" {
				continue
			}
			// Flush unclosed pending attempt before starting a new one.
			if pending != nil && !pending.closed {
				rows = append(rows, pending.row)
			}

			provider := cb.Provider
			if provider == "" {
				provider = lastProvider
			}
			model := cb.Model
			if model == "" {
				model = lastModel
			}
			tsEnd := ev.CreatedAt
			tsStart := tsEnd.Add(-time.Duration(cb.DurationMS) * time.Millisecond)

			pending = &pendingAttempt{
				row: AttemptMetricsRow{
					SchemaVersion: AttemptMetricsSchemaVersion,
					AttemptID:    cb.AttemptID,
					BeadID:       beadID,
					TsStart:      tsStart.UTC(),
					TsEnd:        tsEnd.UTC(),
					Harness:      cb.Harness,
					Provider:     provider,
					Model:        model,
					InputTokens:  cb.InputTokens,
					OutputTokens: cb.OutputTokens,
					TotalTokens:  cb.TotalTokens,
					CostUSD:      cb.CostUSD,
					DurationMS:   cb.DurationMS,
					ExitCode:     cb.ExitCode,
				},
			}
			// Consume routing context; it applies to this attempt only.
			lastProvider = ""
			lastModel = ""

		case "review":
			// review events supply the reviewer verdict (APPROVE/BLOCK/REQUEST_CHANGES)
			// for the pending attempt, before the terminal execute-bead event.
			if pending != nil && !pending.closed {
				pending.row.ReviewVerdict = ev.Summary
			}

		case "execute-bead":
			// Close the pending attempt with its outcome.
			if pending != nil && !pending.closed {
				pending.row.Outcome = ev.Summary
				pending.closed = true
				rows = append(rows, pending.row)
			}
		}
	}

	// Flush any unclosed trailing attempt (e.g. file truncated or missing execute-bead).
	if pending != nil && !pending.closed {
		rows = append(rows, pending.row)
	}

	return rows, nil
}

