package cmd

import (
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newWorkMetricsCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "metrics",
		Short: "Attempt metrics utilities",
		Long: `metrics provides utilities for the per-attempt cold-tier metrics layer
stored in .ddx/metrics/attempts.jsonl.

Each row captures one bead-attempt: model, harness, provider, cost, duration,
outcome, and review verdict. The file grows monotonically; use the backfill
subcommand to seed it from existing bead event histories.`,
	}
	cmd.AddCommand(f.newWorkMetricsBackfillCommand())
	return cmd
}

func (f *CommandFactory) newWorkMetricsBackfillCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "backfill",
		Short: "Backfill .ddx/metrics/attempts.jsonl from existing bead events",
		Long: `backfill reads .ddx/attachments/<bead-id>/events.jsonl for every bead
and emits one row per attempt into .ddx/metrics/attempts.jsonl.

The operation is idempotent: rows whose attempt_id already appears in
attempts.jsonl are skipped. Re-running backfill is safe.

Events source: .ddx/attachments/<bead-id>/events.jsonl (NOT .ddx/executions/).`,
		Example: `  # Seed metrics from all existing bead events
  ddx work metrics backfill

  # Machine-readable row count
  ddx work metrics backfill --json`,
		Args: cobra.NoArgs,
		RunE: f.runWorkMetricsBackfill,
	}
	cmd.Flags().Bool("json", false, "Output result as JSON object")
	return cmd
}

func (f *CommandFactory) runWorkMetricsBackfill(cmd *cobra.Command, _ []string) error {
	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

	added, err := agent.BackfillAttemptMetrics(projectRoot)
	if err != nil {
		return fmt.Errorf("metrics backfill: %w", err)
	}

	asJSON, _ := cmd.Flags().GetBool("json")
	if asJSON {
		fmt.Fprintf(cmd.OutOrStdout(), `{"added":%d}`+"\n", added)
		return nil
	}
	fmt.Fprintf(cmd.OutOrStdout(), "backfill complete: %d new row(s) added to .ddx/metrics/attempts.jsonl\n", added)
	return nil
}

